import apiClient from '@/common/lib/api-client';
import type { User } from '@/features/auth/types/auth.types';

export interface PaginatedResponse<T> {
    content: T[];
    hasNext: boolean;
    number: number;
    size: number;
}

export interface FriendDTO {
    friendId: string;
    username: string; // Backend uses 'username' for FriendDTO
    displayName: string;
    avatarUrl: string;
    friendsSince: string;
    isOnline: boolean;
}

export interface FriendRequestsResponse {
    userId: string;
    status: string;
    userDetails: User[]; // User in auth.types uses 'userName'
}

export const getFriends = async (page = 0, size = 30): Promise<PaginatedResponse<FriendDTO>> => {
    const response = await apiClient.get<PaginatedResponse<FriendDTO> | FriendDTO[]>('/friends/', {
        params: { page, size }
    });

    // Backend returns List<FriendDTO> (plain array), not PaginatedResponse
    if (Array.isArray(response.data)) {
        return {
            content: response.data,
            hasNext: false,
            number: page,
            size: response.data.length
        };
    }

    // Handle Spring Slice format (has 'last' instead of 'hasNext')
    const data = response.data as Record<string, unknown>;
    return {
        content: (data.content as FriendDTO[]) ?? [],
        hasNext: data.hasNext !== undefined ? (data.hasNext as boolean) : !(data.last as boolean),
        number: (data.number as number) ?? page,
        size: (data.size as number) ?? size
    };
};

export const getReceivedRequests = async (userId: string, page = 0, size = 30): Promise<PaginatedResponse<FriendRequestsResponse>> => {
    const response = await apiClient.get<PaginatedResponse<FriendRequestsResponse> | FriendRequestsResponse>(`/friends/requests/received/${userId}`, {
        params: { page, size }
    });

    // Backend returns FriendRequestsResponse (single object), not paginated
    const data = response.data;
    if (!data || !('content' in data)) {
        // Wrap single response in paginated format
        const item = data as FriendRequestsResponse;
        return {
            content: item ? [item] : [],
            hasNext: false,
            number: page,
            size: 1
        };
    }

    // Handle paginated format with Spring Slice compatibility
    const paged = data as unknown as Record<string, unknown>;
    return {
        content: (paged.content as FriendRequestsResponse[]) ?? [],
        hasNext: paged.hasNext !== undefined ? (paged.hasNext as boolean) : !(paged.last as boolean),
        number: (paged.number as number) ?? page,
        size: (paged.size as number) ?? size
    };
};

export const getSentRequests = async (userId: string, page = 0, size = 30): Promise<PaginatedResponse<FriendRequestsResponse>> => {
    const response = await apiClient.get<PaginatedResponse<FriendRequestsResponse>>(`/friends/requests/sent/${userId}`, {
        params: { page, size }
    });
    return response.data;
};

export const sendFriendRequest = async (receiverId: string): Promise<void> => {
    await apiClient.post('/friends/request', { receiverId });
};

export const acceptFriendRequest = async (senderId: string): Promise<void> => {
    await apiClient.put('/friends/accept', { senderId });
};

export const rejectFriendRequest = async (senderId: string): Promise<void> => {
    await apiClient.put('/friends/reject', { senderId });
};
